// SYNOPSIS:
//   Computes drift across the Configuration tier — alert/detection rules,
//   tenant policy, integration state, RBAC, threat intel, operator
//   preferences, CASB integration. Field-level diff (one row per
//   StreamName, EntityId, FieldName that changed between observation
//   windows). Sources: PreviewFeatures, AlertServiceConfig, AlertTuning,
//   SuppressionRules, CustomDetections, TenantAllowBlock, ConnectedApps,
//   IntuneConnection, PurviewSharing, RbacDeviceGroups, UnifiedRbacRoles,
//   ThreatAnalytics, UserPreferences, CloudAppsConfig.
//
// PARAMETERS:
//   lookback - ISO 8601 duration, default 7d. How far back to look for the "previous" snapshot.
//   window   - ISO 8601 duration, default 6h. Matches the config-tier poll cadence.
//
// INVOCATION:
//   MDE_Drift_Configuration(7d, 6h) | where StreamName == "MDE_SuppressionRules_CL"
//   MDE_Drift_Configuration()       // applies defaults
//
// NOTES:
//   - Parameterized as a KQL function so workbooks/rules can plumb
//     {TimeRange:value} from the time-picker without forking the parser body.
//   - Drift is computed over the per-stream typed columns (DCR-projected at
//     ingest); RawJson is preserved on each table as a fallback for fields
//     not in the manifest's ProjectionMap, but the parser never re-parses it.

let MDE_Drift_Configuration = (lookback:timespan = 7d, window:timespan = 6h) {
    // Metadata + envelope columns to exclude from field-level diff (these are
    // bookkeeping; only typed data columns from the manifest ProjectionMap
    // count as "fields" for drift detection).
    let metaCols = dynamic(['TimeGenerated', 'SourceStream', 'EntityId', 'RawJson', '_Table', 'Type', 'TenantId']);
    let sources = union withsource=_Table
        MDE_PreviewFeatures_CL,
        MDE_AlertServiceConfig_CL,
        MDE_AlertTuning_CL,
        MDE_SuppressionRules_CL,
        MDE_CustomDetections_CL,
        MDE_TenantAllowBlock_CL,
        MDE_ConnectedApps_CL,
        MDE_IntuneConnection_CL,
        MDE_PurviewSharing_CL,
        MDE_RbacDeviceGroups_CL,
        MDE_UnifiedRbacRoles_CL,
        MDE_ThreatAnalytics_CL,
        MDE_UserPreferences_CL,
        MDE_CloudAppsConfig_CL
        | where TimeGenerated > ago(lookback);
    let current = sources
        | where TimeGenerated > ago(window)
        | summarize arg_max(TimeGenerated, *) by _Table, EntityId
        | extend TypedBag = bag_remove_keys(pack_all(), metaCols);
    let previous = sources
        | where TimeGenerated between (ago(lookback) .. ago(window))
        | summarize arg_max(TimeGenerated, *) by _Table, EntityId
        | extend TypedBag = bag_remove_keys(pack_all(), metaCols);
    current
    | join kind=leftouter previous on _Table, EntityId
    | where hash(tostring(TypedBag)) != hash(tostring(TypedBag1)) or isnull(TypedBag1)
    | extend CurrentFields  = bag_keys(TypedBag)
    | extend PreviousFields = iff(isnull(TypedBag1), dynamic([]), bag_keys(TypedBag1))
    | mv-apply field = set_union(CurrentFields, PreviousFields) to typeof(string) on (
        extend
            NewValue = tostring(TypedBag[tostring(field)]),
            OldValue = tostring(iff(isnull(TypedBag1), '', TypedBag1[tostring(field)]))
        | where NewValue != OldValue
      )
    | project
        TimeGenerated,
        StreamName       = _Table,
        EntityId,
        FieldName        = tostring(field),
        OldValue,
        NewValue,
        SnapshotCurrent  = TimeGenerated,
        SnapshotPrevious = TimeGenerated1,
        ChangeType       = iff(isnull(TypedBag1), "Added", iff(isnull(TypedBag[tostring(field)]), "Removed", "Modified"))
};
MDE_Drift_Configuration

// SYNOPSIS:
//   Computes drift across the Exposure Management (XSPM) tier — set-diff flavor.
//   Sources: AssetRules, XspmInitiatives, ExposureSnapshots, ExposureRecommendations,
//   XspmAttackPaths, XspmChokePoints, XspmTopTargets.
//
//   XSPM streams are graph-structured (attack paths, chokepoints, entry
//   points). Drift here means "which entities were added/removed between
//   snapshots", not "which fields changed within an entity" — same set-diff
//   shape used by the previous P3 Exposure parser, now scoped to the
//   per-Category exposure cadence.
//
// PARAMETERS:
//   lookback - ISO 8601 duration, default 7d. How far back to look for the "previous" snapshot.
//   window   - ISO 8601 duration, default 1h. How recent counts as "current".
//
// INVOCATION:
//   MDE_Drift_Exposure(7d, 1h) | where ChangeType == "Added"
//   MDE_Drift_Exposure()       // applies defaults
//
// NOTES:
//   - Parameterized as a KQL function so workbooks/rules can plumb
//     {TimeRange:value} from the time-picker without forking the parser body.
//   - Snapshot identity is the per-stream typed-column bag (DCR-projected at
//     ingest); RawJson is preserved on each table as a fallback for fields
//     not in the manifest's ProjectionMap, but the parser never re-parses it.
//   - MDE_SecureScoreBreakdown_CL is intentionally omitted: it is publicly
//     covered by Microsoft Graph /security/secureScores. Use the Graph Security
//     data connector for that data.
//   - Removed-stream history lives in docs/STREAMS-REMOVED.md + CHANGELOG.md.

let MDE_Drift_Exposure = (lookback:timespan = 7d, window:timespan = 1h) {
    // Metadata + envelope columns to exclude from the snapshot identity (these
    // are bookkeeping; only typed data columns from the manifest ProjectionMap
    // count as the entity's state for drift detection).
    let metaCols = dynamic(['TimeGenerated', 'SourceStream', 'EntityId', 'RawJson', '_Table', 'Type', 'TenantId']);
    let sources = union withsource=_Table
        MDE_AssetRules_CL,
        MDE_XspmInitiatives_CL,
        MDE_ExposureSnapshots_CL,
        MDE_ExposureRecommendations_CL,
        MDE_XspmAttackPaths_CL,
        MDE_XspmChokePoints_CL,
        MDE_XspmTopTargets_CL
        | where TimeGenerated > ago(lookback);
    let currentSet = sources
        | where TimeGenerated > ago(window)
        | summarize arg_max(TimeGenerated, *) by _Table, EntityId
        | extend CurrentTypedBag = bag_remove_keys(pack_all(), metaCols)
        | project _Table, EntityId, CurrentTypedBag, CurrentTime = TimeGenerated;
    let previousSet = sources
        | where TimeGenerated between (ago(lookback) .. ago(window))
        | summarize arg_max(TimeGenerated, *) by _Table, EntityId
        | extend PreviousTypedBag = bag_remove_keys(pack_all(), metaCols)
        | project _Table, EntityId, PreviousTypedBag, PreviousTime = TimeGenerated;
    // SnapshotCurrent + SnapshotPrevious columns keep the 9-column drift schema
    // consistent across all 4 tier parsers. Downstream analytic rules and
    // workbooks can filter on "seen in snapshot X but not Y" regardless of tier.
    let added = currentSet
        | join kind=leftanti previousSet on _Table, EntityId
        | extend ChangeType = "Added", OldValue = "", NewValue = tostring(CurrentTypedBag),
                 CurrentSnapshot = CurrentTime, PreviousSnapshot = datetime(null);
    let removed = previousSet
        | join kind=leftanti currentSet on _Table, EntityId
        | extend ChangeType = "Removed", OldValue = tostring(PreviousTypedBag), NewValue = "",
                 CurrentSnapshot = datetime(null), PreviousSnapshot = PreviousTime;
    let modified = currentSet
        | join kind=inner previousSet on _Table, EntityId
        | where hash(tostring(CurrentTypedBag)) != hash(tostring(PreviousTypedBag))
        | extend ChangeType = "Modified", OldValue = tostring(PreviousTypedBag), NewValue = tostring(CurrentTypedBag),
                 CurrentSnapshot = CurrentTime, PreviousSnapshot = PreviousTime;
    union added, removed, modified
    | project
        TimeGenerated    = coalesce(CurrentSnapshot, PreviousSnapshot),
        StreamName       = _Table,
        EntityId,
        FieldName        = "",
        OldValue,
        NewValue,
        SnapshotCurrent  = CurrentSnapshot,
        SnapshotPrevious = PreviousSnapshot,
        ChangeType
};
MDE_Drift_Exposure

// SYNOPSIS:
