//   identity + tenant context + metadata long-tail. Field-level diff (one
//   row per StreamName, EntityId, FieldName that changed between observation
//   windows). Sources: AdvancedFeatures, DeviceControlPolicy,
//   WebContentFiltering, SmartScreenConfig, LiveResponseConfig,
//   AuthenticatedTelemetry, PUAConfig, AntivirusPolicy, CustomCollection,
//   TenantContext, TenantWorkloadStatus, SAClassification, IdentityOnboarding,
//   IdentityServiceAccounts, DCCoverage, IdentityAlertThresholds,
//   RemediationAccounts, SecurityBaselines, MtoTenants, LicenseReport,
//   DeviceTimeline.
//
// PARAMETERS:
//   lookback - ISO 8601 duration, default 30d. How far back to look for the "previous" snapshot.
//   window   - ISO 8601 duration, default 1d. Matches the inventory-tier daily poll cadence.
//
// INVOCATION:
//   MDE_Drift_Inventory(30d, 1d) | where StreamName == "MDE_DCCoverage_CL"
//   MDE_Drift_Inventory()        // applies defaults
//
// NOTES:
//   - Parameterized as a KQL function so workbooks/rules can plumb
//     {TimeRange:value} from the time-picker without forking the parser body.
//   - Drift is computed over the per-stream typed columns (DCR-projected at
//     ingest); RawJson is preserved on each table as a fallback for fields
//     not in the manifest's ProjectionMap, but the parser never re-parses it.
//   - MDE_DeviceTimeline_CL is tenant-gated. The table is created at deploy
//     time; unioning it when the tenant has not provisioned the timeline
//     surface yields zero rows but keeps the parser's source list stable.

let MDE_Drift_Inventory = (lookback:timespan = 30d, window:timespan = 1d) {
    // Metadata + envelope columns to exclude from field-level diff (these are
    // bookkeeping; only typed data columns from the manifest ProjectionMap
    // count as "fields" for drift detection).
    let metaCols = dynamic(['TimeGenerated', 'SourceStream', 'EntityId', 'RawJson', '_Table', 'Type', 'TenantId']);
    let sources = union withsource=_Table
        MDE_AdvancedFeatures_CL,
        MDE_DeviceControlPolicy_CL,
        MDE_WebContentFiltering_CL,
        MDE_SmartScreenConfig_CL,
        MDE_LiveResponseConfig_CL,
        MDE_AuthenticatedTelemetry_CL,
        MDE_PUAConfig_CL,
        MDE_AntivirusPolicy_CL,
        MDE_CustomCollection_CL,
        MDE_TenantContext_CL,
        MDE_TenantWorkloadStatus_CL,
        MDE_SAClassification_CL,
        MDE_IdentityOnboarding_CL,
        MDE_IdentityServiceAccounts_CL,
        MDE_DCCoverage_CL,
        MDE_IdentityAlertThresholds_CL,
        MDE_RemediationAccounts_CL,
        MDE_SecurityBaselines_CL,
        MDE_MtoTenants_CL,
        MDE_LicenseReport_CL,
        MDE_DeviceTimeline_CL
        | where TimeGenerated > ago(lookback);
    let current = sources
        | where TimeGenerated > ago(window)
        | summarize arg_max(TimeGenerated, *) by _Table, EntityId
        | extend TypedBag = bag_remove_keys(pack_all(), metaCols);
    let previous = sources
        | where TimeGenerated between (ago(lookback) .. ago(window))
        | summarize arg_max(TimeGenerated, *) by _Table, EntityId
        | extend TypedBag = bag_remove_keys(pack_all(), metaCols);
    current
    | join kind=leftouter previous on _Table, EntityId
    | where hash(tostring(TypedBag)) != hash(tostring(TypedBag1)) or isnull(TypedBag1)
    | extend CurrentFields  = bag_keys(TypedBag)
    | extend PreviousFields = iff(isnull(TypedBag1), dynamic([]), bag_keys(TypedBag1))
    | mv-apply field = set_union(CurrentFields, PreviousFields) to typeof(string) on (
        extend
            NewValue = tostring(TypedBag[tostring(field)]),
            OldValue = tostring(iff(isnull(TypedBag1), '', TypedBag1[tostring(field)]))
        | where NewValue != OldValue
      )
    | project
        TimeGenerated,
        StreamName       = _Table,
        EntityId,
        FieldName        = tostring(field),
        OldValue,
        NewValue,
        SnapshotCurrent  = TimeGenerated,
        SnapshotPrevious = TimeGenerated1,
        ChangeType       = iff(isnull(TypedBag1), "Added", iff(isnull(TypedBag[tostring(field)]), "Removed", "Modified"))
};
MDE_Drift_Inventory

// SYNOPSIS:
//   Computes drift across the Maintenance tier — rare-change long-tail
//   surfaces. Field-level diff. Sources: DataExportSettings (the canonical
//   streaming-API config). The deprecated MDE_StreamingApiConfig_CL stream
//   is intentionally NOT unioned here — it returns 404 on modern tenants and
//   is excluded from the actual poll.
//
// PARAMETERS:
//   lookback - ISO 8601 duration, default 30d. How far back to look for the "previous" snapshot.
//   window   - ISO 8601 duration, default 7d. Matches the maintenance-tier weekly poll cadence.
//
// INVOCATION:
//   MDE_Drift_Maintenance(30d, 7d) | where StreamName == "MDE_DataExportSettings_CL"
//   MDE_Drift_Maintenance()       // applies defaults
//
// NOTES:
//   - Parameterized as a KQL function so workbooks/rules can plumb
//     {TimeRange:value} from the time-picker without forking the parser body.
//   - Drift is computed over the per-stream typed columns (DCR-projected at
//     ingest); RawJson is preserved on each table as a fallback for fields
//     not in the manifest's ProjectionMap, but the parser never re-parses it.
//   - Single-source tier: the union still uses `withsource=_Table` so the
//     output schema is identical to the other tier parsers — operators can
//     write tier-agnostic queries that filter on StreamName.

let MDE_Drift_Maintenance = (lookback:timespan = 30d, window:timespan = 7d) {
    // Metadata + envelope columns to exclude from field-level diff (these are
    // bookkeeping; only typed data columns from the manifest ProjectionMap
    // count as "fields" for drift detection).
    let metaCols = dynamic(['TimeGenerated', 'SourceStream', 'EntityId', 'RawJson', '_Table', 'Type', 'TenantId']);
    let sources = union withsource=_Table
        MDE_DataExportSettings_CL
        | where TimeGenerated > ago(lookback);
    let current = sources
        | where TimeGenerated > ago(window)
        | summarize arg_max(TimeGenerated, *) by _Table, EntityId
        | extend TypedBag = bag_remove_keys(pack_all(), metaCols);
    let previous = sources
        | where TimeGenerated between (ago(lookback) .. ago(window))
        | summarize arg_max(TimeGenerated, *) by _Table, EntityId
        | extend TypedBag = bag_remove_keys(pack_all(), metaCols);
    current
    | join kind=leftouter previous on _Table, EntityId
    | where hash(tostring(TypedBag)) != hash(tostring(TypedBag1)) or isnull(TypedBag1)
    | extend CurrentFields  = bag_keys(TypedBag)
    | extend PreviousFields = iff(isnull(TypedBag1), dynamic([]), bag_keys(TypedBag1))
    | mv-apply field = set_union(CurrentFields, PreviousFields) to typeof(string) on (
        extend
            NewValue = tostring(TypedBag[tostring(field)]),
            OldValue = tostring(iff(isnull(TypedBag1), '', TypedBag1[tostring(field)]))
        | where NewValue != OldValue
      )
    | project
        TimeGenerated,
        StreamName       = _Table,
        EntityId,
        FieldName        = tostring(field),
        OldValue,
        NewValue,
        SnapshotCurrent  = TimeGenerated,
        SnapshotPrevious = TimeGenerated1,
        ChangeType       = iff(isnull(TypedBag1), "Added", iff(isnull(TypedBag[tostring(field)]), "Removed", "Modified"))
};
MDE_Drift_Maintenance

// Note: workbook time-pickers can override the lookback/window via
// {TimeRange:value} — the underlying parsers are parameterized.
//
// Tenant-time-zone caveat: this query uses UTC. If your tenant operates in
// a non-UTC time zone, adjust 9/17 to your local business hours OR convert
// TimeGenerated to local TZ before the comparison.
union (MDE_Drift_Inventory(7d, 1d)), (MDE_Drift_Configuration(7d, 6h)), (MDE_Drift_Maintenance(30d, 7d))
| extend HourOfDay = datetime_part("Hour", TimeGenerated)
| extend DayOfWeek = dayofweek(TimeGenerated)
| where HourOfDay < 9 or HourOfDay >= 17 or DayOfWeek == time(0d) or DayOfWeek == time(6d)

// Implementation: uses the drift parser MDE_Drift_Inventory with the
// ChangeType="Added" filter so it returns only NEW exclusions in the lookback
// window (rather than the full current exclusion list).
//
// Operator response (suggested):
//   1. For each row: review the added exclusion path/hash + the Operator
//      (admin who made the change) + the time
//   2. Verify against your change-management ticket system
//   3. If unauthorized: investigate the admin's session for compromise +
//      remove the exclusion
MDE_Drift_Inventory(90d, 1h)
| where StreamName == "MDE_AntivirusPolicy_CL"
| where ChangeType == "Added"
| where FieldName has "exclusion" or FieldName has "Exclusion"
| project TimeGenerated, EntityId, FieldName, NewValue, ChangeType
| order by TimeGenerated desc

// PARAMETER: $(SERVICE_ACCOUNT_UPN) — bound at ARM deploy time from
// mainTemplate.json deployment parameter. Operator MUST set this in
// createUiDefinition wizard step 2 (auth setup).
let serviceAccountUpn = "$(SERVICE_ACCOUNT_UPN)";
let baselineWindow = 14d;  // Sentinel queryPeriod max is P14D
let detectionWindow = 30m;
// Establish 30-day baseline of countries + IPs the SA normally signs in from
let baseline = SigninLogs
| where TimeGenerated > ago(baselineWindow) and TimeGenerated < ago(detectionWindow)
| where UserPrincipalName =~ serviceAccountUpn
| where ResultType == 0  // successful sign-ins only
| summarize KnownCountries = make_set(LocationDetails.countryOrRegion),
KnownIPs       = make_set(IPAddress);
// Detect anomalies in the last 30 minutes
SigninLogs
| where TimeGenerated > ago(detectionWindow)
| where UserPrincipalName =~ serviceAccountUpn
| extend Country  = tostring(LocationDetails.countryOrRegion)
| extend FailureSignals = case(
ResultType != 0,                                                     "AuthFail-or-MfaChallengeBypass",
Country !in (toscalar(baseline | project KnownCountries)),           "AnomalousCountry",
IPAddress !in (toscalar(baseline | project KnownIPs)),               "AnomalousIP",
""
)
| where FailureSignals != ""
| project TimeGenerated, UserPrincipalName, IPAddress, Country, AppDisplayName,
ResultType, ResultDescription, FailureSignals
